398	// render renders the sites.
399	func (h *HugoSites) render(l logg.LevelLogger, config *BuildCfg) error {
400		l = l.WithField("step", "render")
401		start := time.Now()
402		defer func() {
403			loggers.TimeTrackf(l, start, h.buildCounters.loggFields(), "")
404		}()
405	
406		siteRenderContext := &siteRenderContext{cfg: config, infol: l, multihost: h.Configs.IsMultihost}
407	
408		renderErr := func(err error) error {
409			if err == nil {
410				return nil
411			}
412			// In Hugo 0.141.0 we replaced the special error handling for resources.GetRemote
413			// with the more general try.
414			if strings.Contains(err.Error(), "can't evaluate field Err in type") {
415				if strings.Contains(err.Error(), "resource.Resource") {
416					return fmt.Errorf("%s: Resource.Err was removed in Hugo v0.141.0 and replaced with a new try keyword, see https://gohugo.io/functions/go-template/try/", err)
417				} else if strings.Contains(err.Error(), "template.HTML") {
418					return fmt.Errorf("%s: the return type of transform.ToMath was changed in Hugo v0.141.0 and the error handling replaced with a new try keyword, see https://gohugo.io/functions/go-template/try/", err)
419				}
420			}
421			return err
422		}
423	
424		i := 0
425	
426		for s := range h.allSites(nil) {
427			if s.conf.Segments.Config.SegmentFilter.ShouldExcludeCoarse(segments.SegmentQuery{Site: s.siteVector}) {
428				l.Logf("skip site %s not matching segments set in --renderSegments", s.resolveDimensionNames())
429				continue
430			}
431			siteRenderContext.languageIdx = s.siteVector.Language()
432			h.currentSite = s
433			for siteOutIdx, renderFormat := range s.renderFormats {
434				if s.conf.Segments.Config.SegmentFilter.ShouldExcludeCoarse(segments.SegmentQuery{Output: renderFormat.Name, Site: s.siteVector}) {
435					l.Logf("skip output format %q for site %s not matching segments set in --renderSegments", renderFormat.Name, s.resolveDimensionNames())
436					continue
437				}
438	
439				if err := func() error {
440					rc := tpl.RenderingContext{Site: s, SiteOutIdx: siteOutIdx}
441					h.BuildState.StartStageRender(rc)
442					defer h.BuildState.StopStageRender(rc)
443	
444					siteRenderContext.outIdx = siteOutIdx
445					siteRenderContext.sitesOutIdx = i
446					i++
447	
448					select {
449					case <-h.Done():
450						return nil
451					default:
452						for s2 := range h.allSites(nil) {
453							if err := s2.preparePagesForRender(s == s2, siteRenderContext.sitesOutIdx); err != nil {
454								return err
455							}
456						}
457						if !config.SkipRender {
458							ll := l.WithField("substep", "pages").
459								WithField("site", s.language.Lang).
460								WithField("outputFormat", renderFormat.Name)
461	
462							start := time.Now()
463	
464							if config.PartialReRender {
465								if err := s.renderPages(siteRenderContext); err != nil {
466									return err
467								}
468							} else {
469								if err := s.render(siteRenderContext); err != nil {
470									return renderErr(err)
471								}
472							}
473							loggers.TimeTrackf(ll, start, nil, "")
474						}
475					}
476					return nil
477				}(); err != nil {
478					return err
479				}
480	
481			}
482	
483		}
484	
485		return nil
486	}
