145	// Get is a convenience method to look up shortcode parameters by its key.
146	func (scp *ShortcodeWithPage) Get(key any) any {
147		if scp.Params == nil {
148			return nil
149		}
150		if reflect.ValueOf(scp.Params).Len() == 0 {
151			return nil
152		}
153	
154		var x reflect.Value
155	
156		switch key.(type) {
157		case int64, int32, int16, int8, int:
158			if reflect.TypeOf(scp.Params).Kind() == reflect.Map {
159				// We treat this as a non error, so people can do similar to
160				// {{ $myParam := .Get "myParam" | default .Get 0 }}
161				// Without having to do additional checks.
162				return nil
163			} else if reflect.TypeOf(scp.Params).Kind() == reflect.Slice {
164				idx := int(reflect.ValueOf(key).Int())
165				ln := reflect.ValueOf(scp.Params).Len()
166				if idx > ln-1 {
167					return ""
168				}
169				x = reflect.ValueOf(scp.Params).Index(idx)
170			}
171		case string:
172			if reflect.TypeOf(scp.Params).Kind() == reflect.Map {
173				x = reflect.ValueOf(scp.Params).MapIndex(reflect.ValueOf(key))
174				if !x.IsValid() {
175					return ""
176				}
177			} else if reflect.TypeOf(scp.Params).Kind() == reflect.Slice {
178				// We treat this as a non error, so people can do similar to
179				// {{ $myParam := .Get "myParam" | default .Get 0 }}
180				// Without having to do additional checks.
181				return nil
182			}
183		}
184	
185		return x.Interface()
186	}
