316	const (
317		innerNewlineRegexp = "\n"
318		innerCleanupRegexp = `\A<p>(.*)</p>\n\z`
319		innerCleanupExpand = "$1"
320	)
321	
322	func prepareShortcode(
323		level int,
324		sc *shortcode,
325		parent *ShortcodeWithPage,
326		po *pageOutput,
327		isRenderString bool,
328	) (shortcodeRenderer, error) {
329		p := po.p
330		toParseErr := func(err error) error {
331			source := p.m.content.mustSource()
332			return p.parseError(fmt.Errorf("failed to render shortcode %q: %w", sc.name, err), source, sc.pos)
333		}
334	
335		// Allow the caller to delay the rendering of the shortcode if needed.
336		var fn shortcodeRenderFunc = func(ctx context.Context) ([]byte, bool, error) {
337			if p.m.pageConfigSource.ContentMediaType.IsMarkdown() && sc.doMarkup {
338				// Signal downwards that the content rendered will be
339				// parsed and rendered by Goldmark.
340				ctx = tpl.Context.IsInGoldmark.Set(ctx, true)
341			}
342			r, err := doRenderShortcode(ctx, level, po.p.s.TemplateStore, sc, parent, po, isRenderString)
343			if err != nil {
344				return nil, false, toParseErr(err)
345			}
346	
347			b, hasVariants, err := r.renderShortcode(ctx)
348			if err != nil {
349				return nil, false, toParseErr(err)
350			}
351			return b, hasVariants, nil
352		}
353	
354		return fn, nil
355	}
356	
357	func doRenderShortcode(
358		ctx context.Context,
359		level int,
360		ts *tplimpl.TemplateStore,
361		sc *shortcode,
362		parent *ShortcodeWithPage,
363		po *pageOutput,
364		isRenderString bool,
365	) (shortcodeRenderer, error) {
366		var tmpl *tplimpl.TemplInfo
367		p := po.p
368	
369		// Tracks whether this shortcode or any of its children has template variations
370		// in other languages or output formats. We are currently only interested in
371		// the output formats.
372		var hasVariants bool
373	
374		if sc.isInline {
375			if !p.s.ExecHelper.Sec().EnableInlineShortcodes {
376				return zeroShortcode, nil
377			}
378			templatePath := path.Join("_inline_shortcode", p.Path(), sc.name)
379			if sc.isClosing {
380				templStr := sc.innerString()
381	
382				var err error
383				tmpl, err = ts.TextParse(templatePath, templStr)
384				if err != nil {
385					if isRenderString {
386						return zeroShortcode, p.wrapError(err)
387					}
388					fe := herrors.NewFileErrorFromName(err, p.File().Filename())
389					pos := fe.Position()
390					pos.LineNumber += p.posOffset(sc.pos).LineNumber
391					fe = fe.UpdatePosition(pos)
392					return zeroShortcode, p.wrapError(fe)
393				}
394	
395			} else {
396				// Re-use of shortcode defined earlier in the same page.
397				tmpl = ts.TextLookup(templatePath)
398				if tmpl == nil {
399					return zeroShortcode, fmt.Errorf("no earlier definition of shortcode %q found", sc.name)
400				}
401			}
402		} else {
403			ofCount := map[string]int{}
404			include := func(match *tplimpl.TemplInfo) bool {
405				ofCount[match.D.OutputFormat]++
406				return true
407			}
408			base, layoutDescriptor := po.GetInternalTemplateBasePathAndDescriptor()
409	
410			// With shortcodes/mymarkdown.md (only), this allows {{% mymarkdown %}} when rendering HTML,
411			// but will not resolve any template when doing {{< mymarkdown >}}.
412			layoutDescriptor.AlwaysAllowPlainText = sc.doMarkup
413			q := tplimpl.TemplateQuery{
414				Path:     base,
415				Name:     sc.name,
416				Category: tplimpl.CategoryShortcode,
417				Desc:     layoutDescriptor,
418				Sites:    p.s.siteVector,
419				Consider: include,
420			}
421			v, err := ts.LookupShortcode(q)
422			if v == nil {
423				return zeroShortcode, err
424			}
425			tmpl = v
426			hasVariants = hasVariants || len(ofCount) > 1
427		}
428	
429		data := &ShortcodeWithPage{
430			Ordinal:     sc.ordinal,
431			posOffset:   sc.pos,
432			indentation: sc.indentation,
433			Params:      sc.params,
434			Page:        newPageForShortcode(p),
435			Parent:      parent,
436			Name:        sc.name,
437		}
438	
439		if sc.params != nil {
440			data.IsNamedParams = reflect.TypeOf(sc.params).Kind() == reflect.Map
441		}
442	
443		if len(sc.inner) > 0 {
444			var inner strings.Builder
445			for _, innerData := range sc.inner {
446				switch innerData := innerData.(type) {
447				case string:
448					inner.WriteString(innerData)
449				case *shortcode:
450					s, err := prepareShortcode(level+1, innerData, data, po, isRenderString)
451					if err != nil {
452						return zeroShortcode, err
453					}
454					ss, more, err := s.renderShortcodeString(ctx)
455					hasVariants = hasVariants || more
456					if err != nil {
457						return zeroShortcode, err
458					}
459					inner.WriteString(ss)
460				default:
461					po.p.s.Log.Errorf("Illegal state on shortcode rendering of %q in page %q. Illegal type in inner data: %s ",
462						sc.name, p.File().Path(), reflect.TypeOf(innerData))
463					return zeroShortcode, nil
464				}
465			}
466	
467			// Pre Hugo 0.55 this was the behavior even for the outer-most
468			// shortcode.
469			if sc.doMarkup && (level > 0 || sc.configVersion() == 1) {
470				var err error
471				b, err := p.pageOutput.contentRenderer.ParseAndRenderContent(ctx, []byte(inner.String()), false)
472				if err != nil {
473					return zeroShortcode, err
474				}
475	
476				newInner := b.Bytes()
477	
478				// If the type is “” (unknown) or “markdown”, we assume the markdown
479				// generation has been performed. Given the input: `a line`, markdown
480				// specifies the HTML `<p>a line</p>\n`. When dealing with documents as a
481				// whole, this is OK. When dealing with an `{{ .Inner }}` block in Hugo,
482				// this is not so good. This code does two things:
483				//
484				// 1.  Check to see if inner has a newline in it. If so, the Inner data is
485				//     unchanged.
486				// 2   If inner does not have a newline, strip the wrapping <p> block and
487				//     the newline.
488				switch p.m.pageConfigSource.Content.Markup {
489				case "", "markdown":
490					if match, _ := regexp.MatchString(innerNewlineRegexp, inner.String()); !match {
491						cleaner, err := regexp.Compile(innerCleanupRegexp)
492	
493						if err == nil {
494							newInner = cleaner.ReplaceAll(newInner, []byte(innerCleanupExpand))
495						}
496					}
497				}
498	
499				// TODO(bep) we may have plain text inner templates.
500				data.Inner = template.HTML(newInner)
501			} else {
502				data.Inner = template.HTML(inner.String())
503			}
504	
505		}
506	
507		result, err := renderShortcodeWithPage(ctx, ts, tmpl, data)
508	
509		if err != nil && sc.isInline {
510			fe := herrors.NewFileErrorFromName(err, p.File().Filename())
511			pos := fe.Position()
512			pos.LineNumber += p.posOffset(sc.pos).LineNumber
513			fe = fe.UpdatePosition(pos)
514			return zeroShortcode, fe
515		}
516	
517		if len(sc.inner) == 0 && len(sc.indentation) > 0 {
518			b := bp.GetBuffer()
519			i := 0
520			text.VisitLinesAfter(result, func(line string) {
521				// The first line is correctly indented.
522				if i > 0 {
523					b.WriteString(sc.indentation)
524				}
525				i++
526				b.WriteString(line)
527			})
528	
529			result = b.String()
530			bp.PutBuffer(b)
531		}
532	
533		return prerenderedShortcode{s: result, hasVariants: hasVariants}, err
534	}
535	
536	func (s *shortcodeParseInfo) prepareShortcodesForPage(po *pageOutput, isRenderString bool) (map[string]shortcodeRenderer, error) {
537		rendered := make(map[string]shortcodeRenderer)
538	
539		for _, v := range s.shortcodes {
540			s, err := prepareShortcode(0, v, nil, po, isRenderString)
541			if err != nil {
542				return nil, err
543			}
544			rendered[v.placeholder] = s
545		}
546	
547		return rendered, nil
548	}
