550	func posFromInput(filename string, input []byte, offset int) text.Position {
551		if offset < 0 || offset > len(input) {
552			return text.Position{
553				Filename: filename,
554			}
555		}
556		lf := []byte("\n")
557		input = input[:offset]
558		lineNumber := bytes.Count(input, lf) + 1
559		endOfLastLine := bytes.LastIndex(input, lf)
560	
561		return text.Position{
562			Filename:     filename,
563			LineNumber:   lineNumber,
564			ColumnNumber: offset - endOfLastLine,
565			Offset:       offset,
566		}
567	}
568	
569	// pageTokens state:
570	// - before: positioned just before the shortcode start
571	// - after: shortcode(s) consumed (plural when they are nested)
572	func (s *shortcodeParseInfo) extractShortcode(ordinal, level int, source []byte, pt *pageparser.Iterator) (*shortcode, error) {
573		if s == nil {
574			panic("handler nil")
575		}
576		sc := &shortcode{ordinal: ordinal}
577	
578		// Back up one to identify any indentation.
579		if pt.Pos() > 0 {
580			pt.Backup()
581			item := pt.Next()
582			if item.IsIndentation() {
583				sc.indentation = item.ValStr(source)
584			}
585		}
586	
587		cnt := 0
588		nestedOrdinal := 0
589		nextLevel := level + 1
590		closed := false
591		const errorPrefix = "failed to extract shortcode"
592	
593	Loop:
594		for {
595			currItem := pt.Next()
596			switch {
597			case currItem.IsLeftShortcodeDelim():
598				next := pt.Peek()
599				if next.IsRightShortcodeDelim() {
600					// no name: {{< >}} or {{% %}}
601					return sc, errors.New("shortcode has no name")
602				}
603				if next.IsShortcodeClose() {
604					continue
605				}
606	
607				if cnt > 0 {
608					// nested shortcode; append it to inner content
609					pt.Backup()
610					nested, err := s.extractShortcode(nestedOrdinal, nextLevel, source, pt)
611					nestedOrdinal++
612					if nested != nil && nested.name != "" {
613						s.addName(nested.name)
614					}
615	
616					if err == nil {
617						sc.inner = append(sc.inner, nested)
618					} else {
619						return sc, err
620					}
621	
622				} else {
623					sc.doMarkup = currItem.IsShortcodeMarkupDelimiter()
624				}
625	
626				cnt++
627	
628			case currItem.IsRightShortcodeDelim():
629				// we trust the template on this:
630				// if there's no inner, we're done
631				if !sc.isInline {
632					if !sc.templ.ParseInfo.IsInner {
633						return sc, nil
634					}
635				}
636	
637			case currItem.IsShortcodeClose():
638				closed = true
639				next := pt.Peek()
640				if !sc.isInline {
641					if !sc.needsInner() {
642						if next.IsError() {
643							// return that error, more specific
644							continue
645						}
646						name := sc.name
647						if name == "" {
648							name = next.ValStr(source)
649						}
650						return nil, fmt.Errorf("%s: shortcode %q does not evaluate .Inner or .InnerDeindent, yet a closing tag was provided", errorPrefix, name)
651					}
652				}
653				if next.IsRightShortcodeDelim() {
654					// self-closing
655					pt.Consume(1)
656				} else {
657					sc.isClosing = true
658					pt.Consume(2)
659				}
660				return sc, nil
661			case currItem.IsText():
662				sc.inner = append(sc.inner, currItem.ValStr(source))
663			case currItem.IsShortcodeName():
664	
665				sc.name = currItem.ValStr(source)
666	
667				// Used to check if the template expects inner content,
668				// so just pick one arbitrarily with the same name.
669				templ := s.firstTemplateStore.LookupShortcodeByName(sc.name)
670				if templ == nil {
671					return nil, fmt.Errorf("%s: template for shortcode %q not found", errorPrefix, sc.name)
672				}
673				sc.templ = templ
674			case currItem.IsInlineShortcodeName():
675				sc.name = currItem.ValStr(source)
676				sc.isInline = true
677			case currItem.IsShortcodeParam():
678				if !pt.IsValueNext() {
679					continue
680				} else if pt.Peek().IsShortcodeParamVal() {
681					// named params
682					if sc.params == nil {
683						params := make(map[string]any)
684						params[currItem.ValStr(source)] = pt.Next().ValTyped(source)
685						sc.params = params
686					} else {
687						if params, ok := sc.params.(map[string]any); ok {
688							params[currItem.ValStr(source)] = pt.Next().ValTyped(source)
689						} else {
690							return sc, fmt.Errorf("%s: invalid state: invalid param type %T for shortcode %q, expected a map", errorPrefix, params, sc.name)
691						}
692					}
693				} else {
694					// positional params
695					if sc.params == nil {
696						var params []any
697						params = append(params, currItem.ValTyped(source))
698						sc.params = params
699					} else {
700						if params, ok := sc.params.([]any); ok {
701							params = append(params, currItem.ValTyped(source))
702							sc.params = params
703						} else {
704							return sc, fmt.Errorf("%s: invalid state: invalid param type %T for shortcode %q, expected a slice", errorPrefix, params, sc.name)
705						}
706					}
707				}
708			case currItem.IsDone():
709				if !currItem.IsError() {
710					if !closed && sc.needsInner() {
711						return sc, fmt.Errorf("%s: shortcode %q must be closed or self-closed", errorPrefix, sc.name)
712					}
713				}
714				// handled by caller
715				pt.Backup()
716				break Loop
717	
718			}
719		}
720		return sc, nil
721	}
722	
723	// Replace prefixed shortcode tokens with the real content.
724	// Note: This function will rewrite the input slice.
725	func expandShortcodeTokens(
726		ctx context.Context,
727		source []byte,
728		tokenHandler func(ctx context.Context, token string) ([]byte, error),
729	) ([]byte, error) {
730		start := 0
731	
732		pre := []byte(shortcodePlaceholderPrefix)
733		post := []byte("HBHB")
734		pStart := []byte("<p>")
735		pEnd := []byte("</p>")
736	
737		k := bytes.Index(source[start:], pre)
738	
739		for k != -1 {
740			j := start + k
741			postIdx := bytes.Index(source[j:], post)
742			if postIdx < 0 {
743				// this should never happen, but let the caller decide to panic or not
744				return nil, errors.New("illegal state in content; shortcode token missing end delim")
745			}
746	
747			end := j + postIdx + 4
748			key := string(source[j:end])
749			newVal, err := tokenHandler(ctx, key)
750			if err != nil {
751				return nil, err
752			}
753	
754			// Issue #1148: Check for wrapping p-tags <p>
755			if j >= 3 && bytes.Equal(source[j-3:j], pStart) {
756				if (k+4) < len(source) && bytes.Equal(source[end:end+4], pEnd) {
757					j -= 3
758					end += 4
759				}
760			}
761	
762			// This and other cool slice tricks: https://github.com/golang/go/wiki/SliceTricks
763			source = append(source[:j], append(newVal, source[end:]...)...)
764			start = j
765			k = bytes.Index(source[start:], pre)
766	
767		}
768	
769		return source, nil
770	}
