772	func renderShortcodeWithPage(ctx context.Context, h *tplimpl.TemplateStore, tmpl *tplimpl.TemplInfo, data *ShortcodeWithPage) (string, error) {
773		buffer := bp.GetBuffer()
774		defer bp.PutBuffer(buffer)
775	
776		err := h.ExecuteWithContext(ctx, tmpl, buffer, data)
777		if err != nil {
778			return "", fmt.Errorf("failed to process shortcode: %w", err)
779		}
780		return buffer.String(), nil
781	}
