273	func (c *goldmarkConverter) Parse(ctx converter.RenderContext) (converter.ResultParse, error) {
274		pctx := c.newParserContext(ctx)
275		reader := text.NewReader(ctx.Src)
276	
277		doc := c.md.Parser().Parse(
278			reader,
279			parser.WithContext(pctx),
280		)
281		doc.OwnerDocument().AddMeta("documentID", c.ctx.DocumentID)
282	
283		return parserResult{
284			doc: doc,
285			toc: pctx.TableOfContents(),
286		}, nil
287	}
