289	func (c *goldmarkConverter) Render(ctx converter.RenderContext, doc any) (converter.ResultRender, error) {
290		n := doc.(ast.Node)
291		buf := &render.BufWriter{Buffer: &bytes.Buffer{}}
292	
293		rcx := &render.RenderContextDataHolder{
294			Rctx: ctx,
295			Dctx: c.ctx,
296		}
297	
298		w := &render.Context{
299			BufWriter:   buf,
300			ContextData: rcx,
301		}
302	
303		if err := c.md.Renderer().Render(w, ctx.Src, n); err != nil {
304			return nil, err
305		}
306	
307		return renderResult{
308			ResultRender: buf,
309		}, nil
310	}
311	
312	func (c *goldmarkConverter) Convert(ctx converter.RenderContext) (converter.ResultRender, error) {
313		parseResult, err := c.Parse(ctx)
314		if err != nil {
315			return nil, err
316		}
317		renderResult, err := c.Render(ctx, parseResult.Doc())
318		if err != nil {
319			return nil, err
320		}
321		return converterResult{
322			ResultRender:            renderResult,
323			tableOfContentsProvider: parseResult,
324		}, nil
325	}
