348	func toTypographicPunctuationMap(t goldmark_config.Typographer) map[extension.TypographicPunctuation][]byte {
349		return map[extension.TypographicPunctuation][]byte{
350			extension.LeftSingleQuote:  []byte(t.LeftSingleQuote),
351			extension.RightSingleQuote: []byte(t.RightSingleQuote),
352			extension.LeftDoubleQuote:  []byte(t.LeftDoubleQuote),
353			extension.RightDoubleQuote: []byte(t.RightDoubleQuote),
354			extension.EnDash:           []byte(t.EnDash),
355			extension.EmDash:           []byte(t.EmDash),
356			extension.Ellipsis:         []byte(t.Ellipsis),
357			extension.LeftAngleQuote:   []byte(t.LeftAngleQuote),
358			extension.RightAngleQuote:  []byte(t.RightAngleQuote),
359			extension.Apostrophe:       []byte(t.Apostrophe),
360		}
361	}
