61	func (ctx *Context) GetAndIncrementOrdinal(kind ast.NodeKind) int {
62		if ctx.ordinals == nil {
63			ctx.ordinals = make(map[ast.NodeKind]int)
64		}
65		i := ctx.ordinals[kind]
66		ctx.ordinals[kind]++
67		return i
