101	// PopPid pops the last page ID from the stack.
102	func (ctx *Context) PopPid() uint64 {
103		if len(ctx.pids) == 0 {
104			return 0
105		}
106		i := len(ctx.pids) - 1
107		p := ctx.pids[i]
108		ctx.pids = ctx.pids[:i]
109		return p
