119	func (ctx *Context) PopValue(k ast.NodeKind) any {
120		if ctx.values == nil {
121			return nil
122		}
123		v := ctx.values[k]
124		if len(v) == 0 {
125			return nil
126		}
127		i := len(v) - 1
128		r := v[i]
129		ctx.values[k] = v[:i]
130		return r
