229	// TextPlain returns a plain text representation of the given node.
230	// This will resolve any leftover HTML entities. This will typically be
231	// entities inserted by e.g. the typographer extension.
232	// Goldmark's Node.Text was deprecated in 1.7.8.
233	func TextPlain(n ast.Node, source []byte) string {
234		buf := bp.GetBuffer()
235		defer bp.PutBuffer(buf)
236	
237		for c := n.FirstChild(); c != nil; c = c.NextSibling() {
238			textPlainTo(c, source, buf)
239		}
240		return string(util.ResolveEntityNames(buf.Bytes()))
241	}
242	
243	func textPlainTo(c ast.Node, source []byte, buf *bytes.Buffer) {
244		if c == nil {
245			return
246		}
247	
248		switch c := c.(type) {
249		case *ast.RawHTML:
250			s := strings.TrimSpace(tpl.StripHTML(string(c.Segments.Value(source))))
251			buf.WriteString(s)
252		case *ast.String:
253			buf.Write(c.Value)
254		case *ast.Text:
255			buf.Write(c.Segment.Value(source))
256			if c.HardLineBreak() || c.SoftLineBreak() {
257				buf.WriteByte('\n')
258			}
259		case *east.Emoji:
260			buf.WriteString(string(c.ShortName))
261		default:
262			textPlainTo(c.FirstChild(), source, buf)
263		}
264	}
