72	func (h chromaHighlighter) Highlight(code, lang string, opts any) (string, error) {
73		cfg := h.cfg
74		if err := applyOptions(opts, &cfg, &lang, &code); err != nil {
75			return "", err
76		}
77		var b strings.Builder
78	
79		if _, _, err := highlight(&b, code, lang, nil, cfg); err != nil {
80			return "", err
81		}
82	
83		return b.String(), nil
84	}
