86	func (h chromaHighlighter) HighlightCodeBlock(ctx hooks.CodeblockContext, opts any) (HighlightResult, error) {
87		cfg := h.cfg
88	
89		var b strings.Builder
90	
91		attributes := ctx.(hooks.AttributesOptionsSliceProvider).AttributesSlice()
92	
93		if err := applyOptionsFromMap(ctx.Options(), &cfg); err != nil {
94			return HighlightResult{}, err
95		}
96	
97		lang, code := ctx.Type(), ctx.Inner()
98	
99		// Apply these last so the user can override them, including the type and code.
100		if err := applyOptions(opts, &cfg, &lang, &code); err != nil {
101			return HighlightResult{}, err
102		}
103	
104		if err := applyOptionsFromCodeBlockContext(ctx, &cfg); err != nil {
105			return HighlightResult{}, err
106		}
107	
108		low, high, err := highlight(&b, code, lang, attributes, cfg)
109		if err != nil {
110			return HighlightResult{}, err
111		}
112	
113		highlighted := b.String()
114		if high == 0 {
115			high = len(highlighted)
116		}
117	
118		return HighlightResult{
119			highlighted: template.HTML(highlighted),
120			innerLow:    low,
121			innerHigh:   high,
122		}, nil
123	}
