165	func highlight(fw hugio.FlexiWriter, code, lang string, attributes []attributes.Attribute, cfg Config) (int, int, error) {
166		var lexer chroma.Lexer
167		if lang != "" {
168			lexer = chromalexers.Get(lang)
169		}
170	
171		if lexer == nil && cfg.GuessSyntax {
172			lexer = lexers.Analyse(code)
173			if lexer == nil {
174				lexer = lexers.Fallback
175			}
176			lang = strings.ToLower(lexer.Config().Name)
177		}
178	
179		w := &byteCountFlexiWriter{delegate: fw}
180	
181		if lexer == nil {
182			if cfg.Hl_inline {
183				fmt.Fprintf(w, "<code%s>%s</code>", inlineCodeAttrs(lang), gohtml.EscapeString(code))
184				return 0, 0, nil
185			}
186	
187			preWrapper := getPreWrapper(lang, w)
188			fmt.Fprint(w, preWrapper.Start(true, ""))
189			fmt.Fprint(w, gohtml.EscapeString(code))
190			fmt.Fprint(w, preWrapper.End(true))
191			return preWrapper.low, preWrapper.high, nil
192		}
193	
194		style := styles.Get(cfg.Style)
195		if style == nil {
196			style = styles.Fallback
197		}
198		lexer = chroma.Coalesce(lexer)
199	
200		iterator, err := lexer.Tokenise(nil, code)
201		if err != nil {
202			return 0, 0, err
203		}
204	
205		if !cfg.Hl_inline {
206			writeDivStart(w, attributes, cfg.WrapperClass)
207		}
208	
209		options, err := cfg.toHTMLOptions()
210		if err != nil {
211			return 0, 0, err
212		}
213	
214		var wrapper html.PreWrapper
215	
216		if cfg.Hl_inline {
217			wrapper = startEnd{
218				start: func(code bool, styleAttr string) string {
219					if code {
220						return fmt.Sprintf(`<code%s>`, inlineCodeAttrs(lang))
221					}
222					return ``
223				},
224				end: func(code bool) string {
225					if code {
226						return `</code>`
227					}
228	
229					return ``
230				},
231			}
232		} else {
233			wrapper = getPreWrapper(lang, w)
234		}
235	
236		options = append(options, html.WithPreWrapper(wrapper))
237	
238		formatter := html.New(options...)
239	
240		if err := formatter.Format(w, style, iterator); err != nil {
241			return 0, 0, err
242		}
243	
244		if !cfg.Hl_inline {
245			writeDivEnd(w)
246		}
247	
