313	func writeDivStart(w hugio.FlexiWriter, attrs []attributes.Attribute, wrapperClass string) {
314		w.WriteString(`<div class="`)
315		w.WriteString(wrapperClass)
316		if attrs != nil {
317			for _, attr := range attrs {
318				if attr.Name == "class" {
319					w.WriteString(" " + attr.ValueString())
320					break
321				}
322			}
323			_, _ = w.WriteString("\"")
324			attributes.RenderAttributes(w, true, attrs...)
325		} else {
326			_, _ = w.WriteString("\"")
327		}
328	
329		w.WriteString(">")
330	}
