56	func (r *htmlRenderer) renderTable(w util.BufWriter, source []byte, n ast.Node, entering bool) (ast.WalkStatus, error) {
57		ctx := w.(*render.Context)
58		if entering {
59			// This will be modified below.
60			table := &hooks.Table{}
61			ctx.PushValue(gast.KindTable, table)
62			return ast.WalkContinue, nil
63		}
64	
65		v := ctx.PopValue(gast.KindTable)
66		if v == nil {
67			panic("table not found")
68		}
69	
70		table := v.(*hooks.Table)
71	
72		renderer := ctx.RenderContext().GetRenderer(hooks.TableRendererType, nil)
73		if renderer == nil {
74			panic("table hook renderer not found")
75		}
76	
77		ordinal := ctx.GetAndIncrementOrdinal(gast.KindTable)
78	
79		tctx := tableContext{
80			BaseContext:      render.NewBaseContext(ctx, renderer, n, source, ordinal),
81			AttributesHolder: attributes.New(n.Attributes(), attributes.AttributesOwnerGeneral),
82			tHead:            table.THead,
83			tBody:            table.TBody,
84		}
85	
86		cr := renderer.(hooks.TableRenderer)
87	
88		err := cr.RenderTable(
89			ctx.RenderContext().Ctx,
90			w,
91			tctx,
92		)
93		if err != nil {
94			return ast.WalkContinue, herrors.NewFileErrorFromPos(err, tctx.Position())
95		}
96	
97		return ast.WalkContinue, nil
98	}
