100	func (r *htmlRenderer) peekTable(ctx *render.Context) *hooks.Table {
101		v := ctx.PeekValue(gast.KindTable)
102		if v == nil {
103			panic("table not found")
104		}
105		return v.(*hooks.Table)
106	}
