108	func (r *htmlRenderer) renderCell(w util.BufWriter, source []byte, node ast.Node, entering bool) (ast.WalkStatus, error) {
109		ctx := w.(*render.Context)
110	
111		if entering {
112			// Store the current pos so we can capture the rendered text.
113			ctx.PushPos(ctx.Buffer.Len())
114			return ast.WalkContinue, nil
115		}
116	
117		n := node.(*gast.TableCell)
118	
119		text := ctx.PopRenderedString()
120	
121		table := r.peekTable(ctx)
122	
123		var alignment string
124		switch n.Alignment {
125		case gast.AlignLeft:
126			alignment = "left"
127		case gast.AlignRight:
128			alignment = "right"
129		case gast.AlignCenter:
130			alignment = "center"
131		default:
132			alignment = ""
133		}
134	
135		cell := hooks.TableCell{Text: hstring.HTML(text), Alignment: alignment}
136	
137		if node.Parent().Kind() == gast.KindTableHeader {
138			table.THead[len(table.THead)-1] = append(table.THead[len(table.THead)-1], cell)
139		} else {
140			table.TBody[len(table.TBody)-1] = append(table.TBody[len(table.TBody)-1], cell)
141		}
142	
143		return ast.WalkContinue, nil
144	}
145	
146	func (r *htmlRenderer) renderHeaderOrRow(w util.BufWriter, source []byte, n ast.Node, entering bool) (ast.WalkStatus, error) {
147		ctx := w.(*render.Context)
148		table := r.peekTable(ctx)
149		if entering {
150			if n.Kind() == gast.KindTableHeader {
151				table.THead = append(table.THead, hooks.TableRow{})
152			} else {
153				table.TBody = append(table.TBody, hooks.TableRow{})
154			}
155			return ast.WalkContinue, nil
156		}
157	
158		return ast.WalkContinue, nil
159	}
