36	func NewConverterProvider(cfg converter.ProviderConfig) (ConverterProvider, error) {
37		converters := make(map[string]converter.Provider)
38	
39		mcfg := cfg.MarkupConfig()
40	
41		if cfg.Highlighter == nil {
42			cfg.Highlighter = highlight.New(mcfg.Highlight)
43		}
44	
45		defaultHandler := mcfg.DefaultMarkdownHandler
46		var defaultFound bool
47	
48		add := func(p converter.ProviderProvider, subType string, aliases ...string) error {
49			c, err := p.New(cfg)
50			if err != nil {
51				return err
52			}
53	
54			name := c.Name()
55	
56			aliases = append(aliases, name)
57			aliases = append(aliases, subType)
58	
59			if strings.EqualFold(name, defaultHandler) {
60				aliases = append(aliases, "markdown")
61				defaultFound = true
62			}
63	
64			addConverter(converters, c, aliases...)
65			return nil
66		}
67	
68		contentTypes := cfg.Conf.ContentTypes().(media.ContentTypes)
69	
70		if err := add(goldmark.Provider, contentTypes.Markdown.SubType, contentTypes.Markdown.Suffixes()...); err != nil {
71			return nil, err
72		}
73		if err := add(asciidocext.Provider, contentTypes.AsciiDoc.SubType, contentTypes.AsciiDoc.Suffixes()...); err != nil {
74			return nil, err
75		}
76		if err := add(rst.Provider, contentTypes.ReStructuredText.SubType, contentTypes.ReStructuredText.Suffixes()...); err != nil {
77			return nil, err
78		}
79		if err := add(pandoc.Provider, contentTypes.Pandoc.SubType, contentTypes.Pandoc.Suffixes()...); err != nil {
80			return nil, err
81		}
82		if err := add(org.Provider, contentTypes.EmacsOrgMode.SubType, contentTypes.EmacsOrgMode.Suffixes()...); err != nil {
83			return nil, err
84		}
85	
86		if !defaultFound {
87			msg := "markup: Configured defaultMarkdownHandler %q not found."
88			if defaultHandler == "blackfriday" {
89				msg += " Did you mean to use goldmark? Blackfriday was removed in Hugo v0.100.0."
90			}
91			return nil, fmt.Errorf(msg, defaultHandler)
92		}
93	
94		return &converterRegistry{
95			config:     cfg,
96			converters: converters,
97		}, nil
98	}
