108	// DedentMarkers removes leading whitespace from Hugo context marker lines
109	// to prevent them from being treated as indented code blocks by Goldmark.
110	func DedentMarkers(b []byte) []byte {
111		if !bytes.Contains(b, hugoCtxPrefix) {
112			return b
113		}
114		return hugoCtxIndentedRe.ReplaceAll(b, []byte("$1"))
115	}
