133	func (s *hugoContextParser) Parse(parent ast.Node, reader text.Reader, pc parser.Context) ast.Node {
134		line, _ := reader.PeekLine()
135		if !bytes.HasPrefix(line, hugoCtxPrefix) {
136			return nil
137		}
138		end := bytes.Index(line, hugoCtxEndDelim)
139		if end == -1 {
140			return nil
141		}
142	
143		reader.Advance(end + len(hugoCtxEndDelim) + 1) // +1 for the newline
144	
145		if line[end-1] == '/' {
146			return &HugoContext{Closing: true}
147		}
148	
149		attrBytes := line[len(hugoCtxPrefix)+1 : end]
150		h := &HugoContext{}
151		h.parseAttrs(attrBytes)
152		return h
153	}
