194	// HTML rendering based on Goldmark implementation.
195	func (r *hugoContextRenderer) renderHTMLBlock(
196		w util.BufWriter, source []byte, node ast.Node, entering bool,
197	) (ast.WalkStatus, error) {
198		n := node.(*ast.HTMLBlock)
199	
200		if entering {
201			if r.Unsafe {
202				l := n.Lines().Len()
203				for i := range l {
204					line := n.Lines().At(i)
205					linev := line.Value(source)
206					var stripped bool
207					linev, stripped = r.stripHugoCtx(linev)
208					if stripped {
209						r.logger.Warnidf(constants.WarnRenderShortcodesInHTML, ".RenderShortcodes detected inside HTML block in %q; this may not be what you intended, see https://gohugo.io/methods/page/rendershortcodes/#limitations", r.getPage(w))
210					}
211					r.Writer.SecureWrite(w, linev)
212				}
213			} else {
214				l := n.Lines().At(0)
215				v := l.Value(source)
216				if !r.isHTMLComment(v) {
217					r.logRawHTMLEmittedWarn(w)
218					_, _ = w.WriteString("<!-- raw HTML omitted -->\n")
219				}
220			}
221		} else {
222			if n.HasClosure() {
223				if r.Unsafe {
224					closure := n.ClosureLine
225					r.Writer.SecureWrite(w, closure.Value(source))
226				} else {
227					l := n.Lines().At(0)
228					v := l.Value(source)
229					if !r.isHTMLComment(v) {
230						_, _ = w.WriteString("<!-- raw HTML omitted -->\n")
231					}
232				}
233			}
234		}
235		return ast.WalkContinue, nil
236	}
