238	func (r *hugoContextRenderer) renderRawHTML(
239		w util.BufWriter, source []byte, node ast.Node, entering bool,
240	) (ast.WalkStatus, error) {
241		if !entering {
242			return ast.WalkSkipChildren, nil
243		}
244		n := node.(*ast.RawHTML)
245		l := n.Segments.Len()
246		if r.Unsafe {
247			for i := range l {
248				segment := n.Segments.At(i)
249				_, _ = w.Write(segment.Value(source))
250			}
251			return ast.WalkSkipChildren, nil
252		}
253		segment := n.Segments.At(0)
254		v := segment.Value(source)
255		if !r.isHTMLComment(v) {
256			r.logRawHTMLEmittedWarn(w)
257			_, _ = w.WriteString("<!-- raw HTML omitted -->")
258		}
259		return ast.WalkSkipChildren, nil
260	}
