262	func (r *hugoContextRenderer) handleHugoContext(w util.BufWriter, source []byte, node ast.Node, entering bool) (ast.WalkStatus, error) {
263		if !entering {
264			return ast.WalkContinue, nil
265		}
266	
267		hctx := node.(*HugoContext)
268		ctx, ok := w.(*render.Context)
269		if !ok {
270			return ast.WalkContinue, nil
271		}
272		if hctx.Closing {
273			_ = ctx.PopPid()
274		} else {
275			ctx.PushPid(hctx.Pid)
276		}
277		return ast.WalkContinue, nil
278	}
