284	func (a *hugoContextTransformer) Transform(n *ast.Document, reader text.Reader, pc parser.Context) {
285		ast.Walk(n, func(n ast.Node, entering bool) (ast.WalkStatus, error) {
286			s := ast.WalkContinue
287			if !entering || n.Kind() != kindHugoContext {
288				return s, nil
289			}
290	
291			if p, ok := n.Parent().(*ast.Paragraph); ok {
292				if p.ChildCount() == 1 {
293					// Avoid empty paragraphs.
294					p.Parent().ReplaceChild(p.Parent(), p, n)
295				} else {
296					if t, ok := n.PreviousSibling().(*ast.Text); ok {
297						// Remove the newline produced by the Hugo context markers.
298						if t.SoftLineBreak() {
299							if t.Segment.Len() == 0 {
300								p.RemoveChild(p, t)
301							} else {
302								t.SetSoftLineBreak(false)
303							}
304						}
305					}
306				}
307			}
308	
309			return s, nil
310		})
311	}
