59	func (r *htmlRenderer) renderCodeBlock(w util.BufWriter, src []byte, node ast.Node, entering bool) (ast.WalkStatus, error) {
60		ctx := w.(*render.Context)
61	
62		if entering {
63			return ast.WalkContinue, nil
64		}
65	
66		n := node.(*ast.FencedCodeBlock)
67	
68		lang := getLang(n, src)
69		renderer := ctx.RenderContext().GetRenderer(hooks.CodeBlockRendererType, lang)
70		if renderer == nil {
71			return ast.WalkStop, fmt.Errorf("no code renderer found for %q", lang)
72		}
73	
74		ordinal := ctx.GetAndIncrementOrdinal(ast.KindFencedCodeBlock)
75	
76		var buff bytes.Buffer
77	
78		l := n.Lines().Len()
79		for i := range l {
80			line := n.Lines().At(i)
81			buff.Write(line.Value(src))
82		}
83	
84		s := htext.Chomp(buff.String())
85	
86		var info []byte
87		if n.Info != nil {
88			info = n.Info.Segment.Value(src)
89		}
90	
91		attrs, attrStr, err := getAttributes(n, info)
92		if err != nil {
93			return ast.WalkStop, &herrors.TextSegmentError{Err: err, Segment: attrStr}
94		}
95	
96		cbctx := codeBlockContext{
97			BaseContext:      render.NewBaseContext(ctx, renderer, node, src, ordinal),
98			lang:             lang,
99			code:             s,
100			AttributesHolder: attributes.New(attrs, attributes.AttributesOwnerCodeBlockChroma),
101		}
102	
103		cr := renderer.(hooks.CodeBlockRenderer)
104	
105		err = cr.RenderCodeblock(
106			ctx.RenderContext().Ctx,
107			w,
108			cbctx,
109		)
110		if err != nil {
111			return ast.WalkContinue, herrors.NewFileErrorFromPos(err, cbctx.Position())
112		}
113	
114		return ast.WalkContinue, nil
115	}
