139	func getAttributes(node *ast.FencedCodeBlock, infostr []byte) ([]ast.Attribute, string, error) {
140		if node.Attributes() != nil {
141			return node.Attributes(), "", nil
142		}
143		if infostr != nil {
144			attrStartIdx := -1
145			attrEndIdx := -1
146	
147			for idx, char := range infostr {
148				if attrEndIdx == -1 && char == '{' {
149					attrStartIdx = idx
150				}
151				if attrStartIdx != -1 && char == '}' {
152					attrEndIdx = idx
153					break
154				}
155			}
156	
157			if attrStartIdx != -1 && attrEndIdx != -1 {
158				n := ast.NewTextBlock() // dummy node for storing attributes
159				attrStr := infostr[attrStartIdx : attrEndIdx+1]
160				if attrs, hasAttr := parser.ParseAttributes(text.NewReader(attrStr)); hasAttr {
161					for _, attr := range attrs {
162						n.SetAttribute(attr.Name, attr.Value)
163					}
164					return n.Attributes(), "", nil
165				} else {
166					return nil, string(attrStr), errors.New("failed to parse Markdown attributes; you may need to quote the values")
167				}
168			}
169		}
170		return nil, "", nil
171	}
