110	func (l *pageLexer) next() rune {
111		if l.pos >= len(l.input) {
112			l.width = 0
113			return eof
114		}
115	
116		runeValue, runeWidth := utf8.DecodeRune(l.input[l.pos:])
117		l.width = runeWidth
118		l.pos += l.width
119	
120		return runeValue
121	}
