183	// special case, do not send '\\' back to client
184	func (l *pageLexer) ignoreEscapesAndEmit(t ItemType, isString bool) {
185		i := l.start
186		k := i
187	
188		var segments []lowHigh
189	
190		for i < l.pos {
191			r, w := utf8.DecodeRune(l.input[i:l.pos])
192			if r == '\\' {
193				if i > k {
194					segments = append(segments, lowHigh{k, i})
195				}
196				// See issue #10236.
197				// We don't send the backslash back to the client,
198				// which makes the end parsing simpler.
199				// This means that we cannot render the AST back to be
200				// exactly the same as the input,
201				// but that was also the situation before we introduced the issue in #10236.
202				k = i + w
203			}
204			i += w
205		}
206	
207		if k < l.pos {
208			segments = append(segments, lowHigh{k, l.pos})
209		}
210	
211		if len(segments) > 0 {
212			l.append(Item{Type: t, segments: segments})
213		}
214	
215		l.start = l.pos
216	}
