279	func (s *sectionHandlers) skip() int {
280		if s.skipAll {
281			return -1
282		}
283	
284		s.skipIndexes = s.skipIndexes[:0]
285		var shouldSkip bool
286		for _, skipper := range s.handlers {
287			idx := skipper.skip()
288			if idx != -1 {
289				shouldSkip = true
290				s.skipIndexes = append(s.skipIndexes, idx)
291			}
292		}
293	
294		if !shouldSkip {
295			s.skipAll = true
296			return -1
297		}
298	
299		return minIndex(s.skipIndexes...)
300	}

