1322	func (h *HugoSites) processContentAdaptersOnRebuild(ctx context.Context, buildConfig *BuildCfg) error {
1323		g := rungroup.Run(ctx, rungroup.Config[*pagesfromdata.PagesFromTemplate]{
1324			NumWorkers: h.numWorkers,
1325			Handle: func(ctx context.Context, p *pagesfromdata.PagesFromTemplate) error {
1326				bi, err := p.Execute(ctx)
1327				if err != nil {
1328					return err
1329				}
1330				s := p.Site.(*Site)
1331				s.handleContentAdapterChanges(bi, buildConfig)
1332				return nil
1333			},
1334		})
1335	
1336		h.pageTrees.treePagesFromTemplateAdapters.WalkPrefixRaw(doctree.LockTypeRead, "", func(key string, p *pagesfromdata.PagesFromTemplate) (bool, error) {
1337			if p.StaleVersion() > 0 {
1338				g.Enqueue(p)
1339			}
1340			return false, nil
1341		})
1342	
1343		return g.Wait()
1344	}
