302	func createSectionHandlers(l *pageLexer) *sectionHandlers {
303		handlers := make([]*sectionHandler, 0, 2)
304	
305		shortCodeHandler := &sectionHandler{
306			l: l,
307			skipFunc: func(l *pageLexer) int {
308				return l.index(leftDelimSc)
309			},
310			lexFunc: func(origin stateFunc, l *pageLexer) (stateFunc, bool) {
311				if !l.isShortCodeStart() {
312					return origin, false
313				}
314	
315				if l.isInline {
316					// If we're inside an inline shortcode, the only valid shortcode markup is
317					// the markup which closes it.
318					b := l.input[l.pos+3:]
319					end := indexNonWhiteSpace(b, '/')
320					if end != len(l.input)-1 {
321						b = bytes.TrimSpace(b[end+1:])
322						if end == -1 || !bytes.HasPrefix(b, []byte(l.currShortcodeName+" ")) {
323							return l.errorf("inline shortcodes do not support nesting"), true
324						}
325					}
326				}
327	
328				if l.hasPrefix(leftDelimScWithMarkup) {
329					l.currLeftDelimItem = tLeftDelimScWithMarkup
330					l.currRightDelimItem = tRightDelimScWithMarkup
331				} else {
332					l.currLeftDelimItem = tLeftDelimScNoMarkup
333					l.currRightDelimItem = tRightDelimScNoMarkup
334				}
335	
336				return lexShortcodeLeftDelim, true
337			},
338		}
339	
340		handlers = append(handlers, shortCodeHandler)
341	
342		if !l.cfg.NoSummaryDivider {
343			summaryDividerHandler := &sectionHandler{
344				l: l,
345				skipFunc: func(l *pageLexer) int {
346					if l.summaryDividerChecked {
347						return -1
348					}
349					return l.index(l.summaryDivider)
350				},
351				lexFunc: func(origin stateFunc, l *pageLexer) (stateFunc, bool) {
352					if !l.hasPrefix(l.summaryDivider) {
353						return origin, false
354					}
355	
356					l.summaryDividerChecked = true
357					l.pos += len(l.summaryDivider)
358					// This makes it a little easier to reason about later.
359					l.consumeSpace()
360					l.emit(TypeLeadSummaryDivider)
361	
362					return origin, true
363				},
364			}
365	
366			handlers = append(handlers, summaryDividerHandler)
367	
368		}
369	
370		return &sectionHandlers{
371			l:           l,
372			handlers:    handlers,
373			skipIndexes: make([]int, len(handlers)),
374		}
375	}
376	
377	func (s *sectionHandlers) lex(origin stateFunc) stateFunc {
378		if s.skipAll {
379			return nil
380		}
381	
382		if s.l.pos > s.l.start {
383			s.l.emit(tText)
384		}
385	
386		for _, handler := range s.handlers {
387			if handler.skipAll {
388				continue
389			}
390	
391			next, handled := handler.lexFunc(origin, handler.l)
392			if next == nil || handled {
393				return next
394			}
395		}
396	
397		// Not handled by the above.
398		s.l.pos++
399	
400		return origin
401	}
