403	type sectionHandler struct {
404		l *pageLexer
405	
406		// No more sections of this type.
407		skipAll bool
408	
409		// Returns the index of the next match, -1 if none found.
410		skipFunc func(l *pageLexer) int
411	
412		// Lex lexes the current section and returns the next state func and
413		// a bool telling if this section was handled.
414		// Note that returning nil as the next state will terminate the
415		// lexer.
416		lexFunc func(origin stateFunc, l *pageLexer) (stateFunc, bool)
417	}
418	
419	func (s *sectionHandler) skip() int {
420		if s.skipAll {
421			return -1
422		}
423	
424		idx := s.skipFunc(s.l)
425		if idx == -1 {
426			s.skipAll = true
427		}
428		return idx
429	}
