431	func lexMainSection(l *pageLexer) stateFunc {
432		if l.isEOF() {
433			return lexDone
434		}
435	
436		// Fast forward as far as possible.
437		skip := l.sectionHandlers.skip()
438	
439		if skip == -1 {
440			l.pos = len(l.input)
441			return lexDone
442		} else if skip > 0 {
443			l.pos += skip
444		}
445	
446		next := l.sectionHandlers.lex(lexMainSection)
447		if next != nil {
448			return next
449		}
450	
451		l.pos = len(l.input)
452		return lexDone
453	}
454	
455	func lexDone(l *pageLexer) stateFunc {
456		// Done!
457		if l.pos > l.start {
458			l.emit(tText)
459		}
460		l.emit(tEOF)
461		return nil
462	}
