481	// returns the min index >= 0
482	func minIndex(indices ...int) int {
483		min := -1
484	
485		for _, j := range indices {
486			if j < 0 {
487				continue
488			}
489			if min == -1 {
490				min = j
491			} else if j < min {
492				min = j
493			}
494		}
495		return min
496	}
