498	func indexNonWhiteSpace(s []byte, in rune) int {
499		idx := bytes.IndexFunc(s, func(r rune) bool {
500			return !isASCIISpace(r)
501		})
502	
503		if idx == -1 {
504			return -1
505		}
506	
507		r, _ := utf8.DecodeRune(s[idx:])
508		if r == in {
509			return idx
510		}
511		return -1
512	}
513	
514	func isASCIISpace(r rune) bool {
515		switch r {
516		case '\t', '\n', '\v', '\f', '\r', ' ':
517			return true
518		}
519		return false
520	}
521	
522	func isAlphaNumericOrHyphen(r rune) bool {
523		// let unquoted YouTube ids as positional params slip through (they contain hyphens)
524		return isAlphaNumeric(r) || r == '-'
525	}
526	
527	var crLf = []rune{'\r', '\n'}
528	
529	func isEndOfLine(r rune) bool {
530		return r == '\r' || r == '\n'
531	}
532	
533	func isAlphaNumeric(r rune) bool {
534		return r == '_' || unicode.IsLetter(r) || unicode.IsDigit(r)
535	}
