18	type lexerShortcodeState struct {
19		currLeftDelimItem  ItemType
20		currRightDelimItem ItemType
21		isInline           bool
22		currShortcodeName  string                         // is only set when a shortcode is in opened state
23		closingState       int                            // > 0 = on its way to be closed
24		elementStepNum     int                            // step number in element
25		paramElements      int                            // number of elements (name + value = 2) found first
26		openShortcodes     map[unique.Handle[string]]bool // set of shortcodes in open state
27	}
