29	// Shortcode syntax
30	var (
31		leftDelimSc            = []byte("{{")
32		leftDelimScNoMarkup    = []byte("{{<")
33		rightDelimScNoMarkup   = []byte(">}}")
34		leftDelimScWithMarkup  = []byte("{{%")
35		rightDelimScWithMarkup = []byte("%}}")
36		leftComment            = []byte("/*") // comments in this context are used to mark shortcodes as "not really a shortcode"
37		rightComment           = []byte("*/")
38	)
39	
40	func (l *pageLexer) isShortCodeStart() bool {
41		return l.hasPrefix(leftDelimScWithMarkup) || l.hasPrefix(leftDelimScNoMarkup)
42	}
43	
44	func lexShortcodeLeftDelim(l *pageLexer) stateFunc {
45		l.pos += len(l.currentLeftShortcodeDelim())
46		if l.hasPrefix(leftComment) {
47			return lexShortcodeComment
48		}
49		l.emit(l.currentLeftShortcodeDelimItem())
50		l.elementStepNum = 0
51		l.paramElements = 0
52		return lexInsideShortcode
53	}
54	
55	func lexShortcodeComment(l *pageLexer) stateFunc {
56		posRightComment := l.index(append(rightComment, l.currentRightShortcodeDelim()...))
57		if posRightComment <= 1 {
58			return l.errorf("comment must be closed")
59		}
60		// we emit all as text, except the comment markers
61		l.emit(tText)
62		l.pos += len(leftComment)
63		l.ignore()
64		l.pos += posRightComment - len(leftComment)
65		l.emit(tText)
66		l.pos += len(rightComment)
67		l.ignore()
68		l.pos += len(l.currentRightShortcodeDelim())
69		l.emit(tText)
70		return lexMainSection
71	}
72	
73	func lexShortcodeRightDelim(l *pageLexer) stateFunc {
74		l.closingState = 0
75		l.pos += len(l.currentRightShortcodeDelim())
76		l.emit(l.currentRightShortcodeDelimItem())
77		return lexMainSection
78	}
