126	func (r *hookedRenderer) renderImage(w util.BufWriter, source []byte, node ast.Node, entering bool) (ast.WalkStatus, error) {
127		n := node.(*ast.Image)
128		var lr hooks.LinkRenderer
129	
130		ctx, ok := w.(*render.Context)
131		if ok {
132			h := ctx.RenderContext().GetRenderer(hooks.ImageRendererType, nil)
133			ok = h != nil
134			if ok {
135				lr = h.(hooks.LinkRenderer)
136			}
137		}
138	
139		if !ok {
140			return r.renderImageDefault(w, source, node, entering)
141		}
142	
143		if entering {
144			// Store the current pos so we can capture the rendered text.
145			ctx.PushPos(ctx.Buffer.Len())
146			return ast.WalkContinue, nil
147		}
148	
149		text := ctx.PopRenderedString()
150	
151		var (
152			isBlock bool
153			ordinal int
154		)
155		if b, ok := n.AttributeString(images.AttrIsBlock); ok && b.(bool) {
156			isBlock = true
157		}
158		if n, ok := n.AttributeString(images.AttrOrdinal); ok {
159			ordinal = n.(int)
160		}
161	
162		// We use the attributes to signal from the parser whether the image is in
163		// a block context or not.
164		// We may find a better way to do that, but for now, we'll need to remove any
165		// internal attributes before rendering.
166		attrs := r.filterInternalAttributes(n.Attributes())
167	
168		err := lr.RenderLink(
169			ctx.RenderContext().Ctx,
170			w,
171			imageLinkContext{
172				linkContext: linkContext{
173					BaseContext:      render.NewBaseContext(ctx, lr, node, source, ordinal),
174					destination:      string(n.Destination),
175					title:            string(n.Title),
176					text:             hstring.HTML(text),
177					plainText:        render.TextPlain(n, source),
178					AttributesHolder: attributes.New(attrs, attributes.AttributesOwnerGeneral),
179				},
180				isBlock: isBlock,
181			},
182		)
183	
184		return ast.WalkContinue, err
185	}
