187	func (r *hookedRenderer) filterInternalAttributes(attrs []ast.Attribute) []ast.Attribute {
188		n := 0
189		for _, x := range attrs {
190			if !bytes.HasPrefix(x.Name, []byte(internalAttrPrefix)) {
191				attrs[n] = x
192				n++
193			}
194		}
195		return attrs[:n]
196	}
