198	// Fall back to the default Goldmark render funcs. Method below borrowed from:
199	// https://github.com/yuin/goldmark
200	func (r *hookedRenderer) renderImageDefault(w util.BufWriter, source []byte, node ast.Node, entering bool) (ast.WalkStatus, error) {
201		if !entering {
202			return ast.WalkContinue, nil
203		}
204		n := node.(*ast.Image)
205		_, _ = w.WriteString("<img src=\"")
206		dest := util.URLEscape(n.Destination, true)
207		if r.Unsafe || !html.IsDangerousURL(dest) {
208			_, _ = w.Write(util.EscapeHTML(dest))
209		}
210		_, _ = w.WriteString(`" alt="`)
211		r.renderTexts(w, source, n)
212		_ = w.WriteByte('"')
213		if n.Title != nil {
214			_, _ = w.WriteString(` title="`)
215			r.Writer.Write(w, n.Title)
216			_ = w.WriteByte('"')
217		}
218		if n.Attributes() != nil {
219			html.RenderAttributes(w, n, html.ImageAttributeFilter)
220		}
221		if r.XHTML {
222			_, _ = w.WriteString(" />")
223		} else {
224			_, _ = w.WriteString(">")
225		}
226		return ast.WalkSkipChildren, nil
227	}
