273		for c := n.FirstChild(); c != nil; c = c.NextSibling() {
274			if s, ok := c.(*ast.String); ok {
275				_, _ = r.renderString(w, source, s, true)
276			} else if t, ok := c.(*ast.Text); ok {
277				_, _ = r.renderText(w, source, t, true)
278			} else {
279				r.renderTexts(w, source, c)
