286		if !entering {
287			return ast.WalkContinue, nil
288		}
289		n := node.(*ast.String)
290		if n.IsCode() {
291			_, _ = w.Write(n.Value)
292		} else {
293			if n.IsRaw() {
294				r.Writer.RawWrite(w, n.Value)
295			} else {
