302	// Borrowed from Goldmark's HTML renderer.
303	func (r *hookedRenderer) renderText(w util.BufWriter, source []byte, node ast.Node, entering bool) (ast.WalkStatus, error) {
304		if !entering {
305			return ast.WalkContinue, nil
306		}
307		n := node.(*ast.Text)
308		segment := n.Segment
309		if n.IsRaw() {
310			r.Writer.RawWrite(w, segment.Value(source))
311		} else {
312			value := segment.Value(source)
313			r.Writer.Write(w, value)
314			if n.HardLineBreak() || (n.SoftLineBreak() && r.HardWraps) {
315				if r.XHTML {
316					_, _ = w.WriteString("<br />\n")
317				} else {
318					_, _ = w.WriteString("<br>\n")
