350			dest := util.URLEscape(n.Destination, true)
351			if r.Unsafe || !html.IsDangerousURL(dest) {
352				_, _ = w.Write(util.EscapeHTML(dest))
353			}
354			_ = w.WriteByte('"')
355			if n.Title != nil {
356				_, _ = w.WriteString(` title="`)
357				r.Writer.Write(w, n.Title)
358				_ = w.WriteByte('"')
359			}
