367	func (r *hookedRenderer) renderAutoLink(w util.BufWriter, source []byte, node ast.Node, entering bool) (ast.WalkStatus, error) {
368		if !entering {
369			return ast.WalkContinue, nil
370		}
371	
372		n := node.(*ast.AutoLink)
373		var lr hooks.LinkRenderer
374	
375		ctx, ok := w.(*render.Context)
376		if ok {
377			h := ctx.RenderContext().GetRenderer(hooks.LinkRendererType, nil)
378			ok = h != nil
379			if ok {
380				lr = h.(hooks.LinkRenderer)
381			}
382		}
383	
384		if !ok {
385			return r.renderAutoLinkDefault(w, source, node, entering)
386		}
387	
388		url := string(r.autoLinkURL(n, source))
389		label := string(n.Label(source))
390		if n.AutoLinkType == ast.AutoLinkEmail && !strings.HasPrefix(strings.ToLower(url), "mailto:") {
391			url = "mailto:" + url
392		}
