394		ordinal := ctx.GetAndIncrementOrdinal(n.Kind())
395	
396		err := lr.RenderLink(
397			ctx.RenderContext().Ctx,
398			w,
399			linkContext{
400				BaseContext:      render.NewBaseContext(ctx, lr, node, source, ordinal),
401				destination:      url,
402				text:             hstring.HTML(label),
403				plainText:        label,
404				AttributesHolder: attributes.Empty,
405			},
406		)
