411	// Fall back to the default Goldmark render funcs. Method below borrowed from:
412	// https://github.com/yuin/goldmark/blob/5588d92a56fe1642791cf4aa8e9eae8227cfeecd/renderer/html/html.go#L439
413	func (r *hookedRenderer) renderAutoLinkDefault(w util.BufWriter, source []byte, node ast.Node, entering bool) (ast.WalkStatus, error) {
414		n := node.(*ast.AutoLink)
415		if !entering {
416			return ast.WalkContinue, nil
417		}
418	
419		_, _ = w.WriteString(`<a href="`)
420		url := util.URLEscape(r.autoLinkURL(n, source), false)
421	
422		label := n.Label(source)
423		if n.AutoLinkType == ast.AutoLinkEmail && !bytes.HasPrefix(bytes.ToLower(url), []byte("mailto:")) {
424			_, _ = w.WriteString("mailto:")
425		}
426		if r.Unsafe || !html.IsDangerousURL(url) {
427			_, _ = w.Write(util.EscapeHTML(url))
428		}
429		if n.Attributes() != nil {
430			_ = w.WriteByte('"')
431			html.RenderAttributes(w, n, html.LinkAttributeFilter)
432			_ = w.WriteByte('>')
433		} else {
434			_, _ = w.WriteString(`">`)
435		}
436		_, _ = w.Write(util.EscapeHTML(label))
437		_, _ = w.WriteString(`</a>`)
438		return ast.WalkContinue, nil
439	}
