441	func (r *hookedRenderer) autoLinkURL(n *ast.AutoLink, source []byte) []byte {
442		url := n.URL(source)
443		if len(n.Protocol) > 0 && !bytes.Equal(n.Protocol, r.linkifyProtocol) {
444			// The CommonMark spec says "http" is the correct protocol for links,
445			// but this doesn't make much sense (the fact that they should care about the rendered output).
446			// Note that n.Protocol is not set if protocol is provided by user.
447			url = append(r.linkifyProtocol, url[len(n.Protocol):]...)
448		}
449		return url
450	}
