36	func sanitizeAnchorNameString(s string, idType string) string {
37		return string(sanitizeAnchorName([]byte(s), idType))
38	}
39	
40	func sanitizeAnchorName(b []byte, idType string) []byte {
41		return sanitizeAnchorNameWithHook(b, idType, nil)
42	}
43	
44	func sanitizeAnchorNameWithHook(b []byte, idType string, hook func(buf *bytes.Buffer)) []byte {
45		buf := bp.GetBuffer()
46	
47		if idType == goldmark_config.AutoIDTypeBlackfriday {
48			// TODO(bep) make it more efficient.
49			buf.WriteString(blackfriday.SanitizedAnchorName(string(b)))
50		} else {
51			asciiOnly := idType == goldmark_config.AutoIDTypeGitHubAscii
52	
53			if asciiOnly {
54				// Normalize it to preserve accents if possible.
55				b = text.RemoveAccents(b)
56			}
57	
58			b = bytes.TrimSpace(b)
59	
60			for len(b) > 0 {
61				r, size := utf8.DecodeRune(b)
62				switch {
63				case asciiOnly && size != 1:
64				case r == '-' || r == ' ':
65					buf.WriteRune('-')
66				case isAlphaNumeric(r):
67					buf.WriteRune(unicode.ToLower(r))
68				default:
69				}
70	
71				b = b[size:]
72			}
73		}
74	
75		if hook != nil {
76			hook(buf)
77		}
78	
79		result := make([]byte, buf.Len())
80		copy(result, buf.Bytes())
81	
82		bp.PutBuffer(buf)
83	
84		return result
85	}
86	
87	func isAlphaNumeric(r rune) bool {
88		return r == '_' || unicode.IsLetter(r) || unicode.IsDigit(r)
89	}
