121	func (ids *idFactory) Generate(value []byte, kind ast.NodeKind) []byte {
122		return sanitizeAnchorNameWithHook(value, ids.idType, func(buf *bytes.Buffer) {
123			if buf.Len() == 0 {
124				if kind == ast.KindHeading {
125					buf.WriteString("heading")
126				} else if kind == east.KindDefinitionTerm {
127					buf.WriteString("term")
128				} else {
129					buf.WriteString("id")
130				}
131			}
132	
133			if _, found := ids.vals[util.BytesToReadOnlyString(buf.Bytes())]; found {
134				// Append a hyphen and a number, starting with 1.
135				buf.WriteRune('-')
136				pos := buf.Len()
137				for i := 1; ; i++ {
138					buf.WriteString(strconv.Itoa(i))
139					if _, found := ids.vals[util.BytesToReadOnlyString(buf.Bytes())]; !found {
140						break
141					}
142					buf.Truncate(pos)
143				}
144			}
145			ids.put(buf.String())
146		})
147	}
148	
149	func (ids *idFactory) put(s string) {
150		if _, found := ids.vals[s]; found {
151			ids.duplicates = append(ids.duplicates, s)
152		} else {
153			ids.vals[s] = struct{}{}
154		}
155	}
156	
157	func (ids *idFactory) Put(value []byte) {
158		ids.put(string(value))
159	}
