1789			return err
1790		}
1791	
1792		if err = s.renderPages(ctx); err != nil {
1793			return
1794		}
1795	
1796		if !ctx.shouldRenderStandalonePage("") {
1797			return
1798		}
1799	
1800		return
1801	}
