254	func (ps *pageState) lookupContentNodes(vec sitesmatrix.Vector, fallback bool) iter.Seq[contentNodeForSite] {
255		nop := func(yield func(n contentNodeForSite) bool) {}
256		pc := ps.m.pageConfigSource
257		if !fallback {
258			if !pc.MatchSiteVector(vec) {
259				return nop
260			}
261			return func(yield func(n contentNodeForSite) bool) {
262				yield(ps)
263			}
264		}
265	
266		if !pc.MatchLanguageCoarse(vec) {
267			return nop
268		}
269	
270		if !pc.MatchVersionCoarse(vec) {
271			return nop
272		}
273		if !pc.MatchRoleCoarse(vec) {
274			return nop
275		}
276	
277		return func(yield func(n contentNodeForSite) bool) {
278			yield(ps)
279		}
280	}
