1333			},
1334		})
1335	
1336		h.pageTrees.treePagesFromTemplateAdapters.WalkPrefixRaw(doctree.LockTypeRead, "", func(key string, p *pagesfromdata.PagesFromTemplate) (bool, error) {
1337			if p.StaleVersion() > 0 {
1338				g.Enqueue(p)
1339			}
1340			return false, nil
1341		})
